const raw = $input.first().json;
const text = String(raw.query ?? raw.chatInput ?? raw.search ?? '').trim();
if (!text || text.length < 3) {
  return [{ json: { search: null, response: 'Provide a search term (e.g. McpTrigger or AI Agent memory).' } }];
}
return [{ json: { search: text.slice(0, 120) } }];

const parsed = $('Parse search').first().json;
if (!parsed.search) {
  return [{ json: { response: parsed.response || 'Provide a search term (e.g. McpTrigger).' } }];
}
const search = parsed.search;
const q = `repo:n8n-io/n8n ${search}`;
const res = await this.helpers.httpRequestWithAuthentication.call(this, 'githubApi', {
  method: 'GET',
  url: `https://api.github.com/search/code?q=${encodeURIComponent(q)}&per_page=10`,
  json: true,
});
const items = (res.items || []).filter((x) => x.path);
if (!items.length) {
  return [{ json: { response: `No code matches for "${search}" in n8n-io/n8n.` } }];
}
const md = items.slice(0, 8).map((f) => {
  const url = f.html_url || `https://github.com/n8n-io/n8n/blob/master/${f.path}`;
  return `• ${f.path} — ${url}`;
}).join('\n');
return [{
  json: {
    response: `Code scout (read-only) for "${search}" in n8n-io/n8n:\n\n${md}\n\n_Use these paths as hypotheses — verify before patching._`,
  },
}];
